`timescale 1ns / 1ps
 
module testbench_labtest2_combinational;
 
    integer count;
    
    // ------------------ Specify variables generated by testbench ------------------ 
    reg[3:0] a, b, d;
    reg c;
    
    // ------------------ Specify variables that are watched by testbench ------------------ 
    wire[3:0] x;
    
    labtest_q2_hardware dut(.a(a),.b(b),
                                .c(c),.d(d),
                                .x(x));
 
    // ------------------ Setup inputs ------------------
    // Provide initial values for inputs. The ‘initial’ command
    // is only valid within the testbench.
    // Can use this for all simple testbenches
    initial begin 
        count = 0;
    end
 
    always begin
        #50
        count=count+1;
    end
 
    // Toggle inputs at different rates to cover all input  
    always @(count) begin
        case (count)
            1 : begin a<=4'b0110; b<=4'b1111; c<=1'b0; d<=4'b0100; end 
            2 : begin a<=4'b0010; b<=4'b1101; c<=1'b0; d<=4'b0101; end
            default : begin a<=4'b0000; b<=4'b0000; c<=1'b0;  d<=4'b0000; end 
        endcase
    end

    initial begin

        $dumpfile("testbench_labtest2_combinational.vcd");
        $dumpvars(0, testbench_labtest2_combinational);
        #1000 
        $finish;

	end
 
endmodule
